SELECT id, category_name, description, icon_url, sort_order, status FROM scenic_category
AND status = #{status}
ORDER BY sort_order ASC

SELECT id, category_name, description, icon_url, sort_order, status, create_time, update_time FROM scenic_category
AND status = #{status}
AND is_deleted = 0
ORDER BY sort_order ASC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM scenic_category
AND status = #{status}
AND is_deleted = 0
